611→    proptest! {
612→        /// Fingerprints are deterministic: same inputs always produce the same hash.
613→        #[test]
614→        fn fingerprint_deterministic(
615→            source in ".*",
616→            analysis in arb_function_analysis(),
617→        ) {
618→            let fp1 = compute_function_fingerprint(&source, &analysis);
619→            let fp2 = compute_function_fingerprint(&source, &analysis);
620→            prop_assert_eq!(&fp1, &fp2);
621→        }
622→
623→        /// Fingerprints are always 64-character hex strings (SHA-256).
624→        #[test]
625→        fn fingerprint_length_invariant(
626→            source in ".*",
627→            analysis in arb_function_analysis(),
628→        ) {
629→            let fp = compute_function_fingerprint(&source, &analysis);
630→            prop_assert_eq!(fp.len(), 64);
631→            prop_assert!(fp.chars().all(|c| c.is_ascii_hexdigit()));
632→        }
633→
634→        /// Deep fingerprints are deterministic.
635→        #[test]
636→        fn deep_fingerprint_deterministic(
637→            shallow in "[a-f0-9]{64}",
638→            callee_name in "[a-z_]{1,20}",
639→            callee_fp in "[a-f0-9]{64}",
640→        ) {
641→            let callee_fps: HashMap<String, String> =
642→                [(callee_name.clone(), callee_fp)].into_iter().collect();
643→            let callees: HashSet<String> = [callee_name].into_iter().collect();
644→
645→            let fp1 = compute_deep_fingerprint(&shallow, &callee_fps, &callees);
646→            let fp2 = compute_deep_fingerprint(&shallow, &callee_fps, &callees);
647→            prop_assert_eq!(&fp1, &fp2);
648→        }
649→
650→        /// Deep fingerprints are always 64-character hex strings.
651→        #[test]
652→        fn deep_fingerprint_length_invariant(
653→            shallow in "[a-f0-9]{64}",
654→        ) {
655→            let fp = compute_deep_fingerprint(&shallow, &HashMap::new(), &HashSet::new());
656→            prop_assert_eq!(fp.len(), 64);
657→            prop_assert!(fp.chars().all(|c| c.is_ascii_hexdigit()));
658→        }
659→
660→        /// Different source text produces different fingerprints (collision resistance).
661→        #[test]
662→        fn different_source_different_fingerprint(
663→            src1 in ".{1,100}",
664→            src2 in ".{1,100}",
665→            analysis in arb_function_analysis(),
666→        ) {
667→            prop_assume!(src1 != src2);
668→            let fp1 = compute_function_fingerprint(&src1, &analysis);
669→            let fp2 = compute_function_fingerprint(&src2, &analysis);
670→            prop_assert_ne!(fp1, fp2);
671→        }
672→    }
673→}
