   1→//! Call graph construction from a [`FunctionRegistry`].
   2→//!
   3→//! Builds a directed graph where edges represent intra-project function calls.
   4→//! Provides topological layering (for bottom-up exploration order) and cycle
   5→//! detection via Tarjan's strongly connected components algorithm.
   6→
   7→use std::collections::{HashMap, HashSet};
   8→
   9→use crate::batch_analyze::FunctionRegistry;
  10→
  11→/// A directed call graph over functions in a [`FunctionRegistry`].
  12→#[derive(Debug, Clone)]
  13→pub struct CallGraph {
  14→    /// All node names (qualified names) in insertion order.
  15→    nodes: Vec<String>,
  16→    /// Map from qualified name to node index.
  17→    node_index: HashMap<String, usize>,
  18→    /// Adjacency list: adj[caller_idx] = vec of callee indices.
  19→    adj: Vec<Vec<usize>>,
  20→    /// Reverse adjacency: rev[callee_idx] = vec of caller indices.
  21→    rev: Vec<Vec<usize>>,
  22→}
  23→
  24→/// An edge in the call graph.
  25→#[derive(Debug, Clone, PartialEq, Eq)]
  26→pub struct Edge {
  27→    /// Qualified name of the caller.
  28→    pub caller: String,
  29→    /// Qualified name of the callee.
  30→    pub callee: String,
  31→}
  32→
  33→/// A batch of functions that can be explored in parallel.
  34→///
  35→/// All functions in a batch are independent of each other: they either have
  36→/// no callees in the graph, or all their callees appear in earlier batches.
  37→/// Functions in a cycle (strongly connected component) are grouped into the
  38→/// same batch because they must be explored together.
  39→#[derive(Debug, Clone, PartialEq, Eq)]
  40→pub struct ExplorationBatch {
  41→    /// The layer index (0 = leaves, higher = closer to entry points).
  42→    pub layer: usize,
  43→    /// Functions in this batch. Each inner `Vec` is one strongly connected
  44→    /// component. Single-element vecs are acyclic functions; multi-element
  45→    /// vecs are mutual-recursion groups.
  46→    pub groups: Vec<Vec<String>>,
  47→}
  48→
  49→impl CallGraph {
  50→    /// Build a call graph from a [`FunctionRegistry`].
  51→    ///
  52→    /// An edge from A to B is added when A has an `ExternalDependency` whose
  53→    /// `symbol` matches the function name portion of some entry B in the registry.
  54→    /// When multiple entries share the same function name, the dependency's
  55→    /// `source_module` is checked against candidate file paths to disambiguate.
  56→    pub fn from_registry(registry: &FunctionRegistry) -> Self {
  57→        let entries = registry.entries();
  58→
  59→        // Build node list and index.
  60→        let mut nodes = Vec::with_capacity(entries.len());
  61→        let mut node_index = HashMap::with_capacity(entries.len());
  62→        for entry in entries {
  63→            let qn = FunctionRegistry::qualified_name(&entry.file_path, &entry.name);
  64→            let idx = nodes.len();
  65→            node_index.insert(qn.clone(), idx);
  66→            nodes.push(qn);
  67→        }
  68→
  69→        let mut adj = vec![Vec::new(); nodes.len()];
  70→        let mut rev = vec![Vec::new(); nodes.len()];
  71→
  72→        // Build a name-to-indices map for resolving dependencies by symbol name.
  73→        let mut name_to_indices: HashMap<&str, Vec<usize>> = HashMap::new();
  74→        for (i, entry) in entries.iter().enumerate() {
  75→            name_to_indices
  76→                .entry(&entry.name)
  77→                .or_default()
  78→                .push(i);
  79→        }
  80→
  81→        for (caller_idx, entry) in entries.iter().enumerate() {
  82→            for dep in &entry.dependencies {
  83→                let callee_idx = resolve_dependency(
  84→                    &dep.symbol,
  85→                    &dep.source_module,
  86→                    &name_to_indices,
  87→                    entries,
  88→                );
  89→                if let Some(ci) = callee_idx
  90→                    && ci != caller_idx
  91→                {
  92→                    adj[caller_idx].push(ci);
  93→                    rev[ci].push(caller_idx);
  94→                }
  95→            }
  96→        }
  97→
  98→        CallGraph {
  99→            nodes,
 100→            node_index,
 101→            adj,
 102→            rev,
 103→        }
 104→    }
 105→
 106→    /// Number of nodes in the graph.
 107→    pub fn node_count(&self) -> usize {
 108→        self.nodes.len()
 109→    }
 110→
 111→    /// Number of directed edges.
 112→    pub fn edge_count(&self) -> usize {
 113→        self.adj.iter().map(|v| v.len()).sum()
 114→    }
 115→
 116→    /// Iterate all edges as `(caller, callee)` qualified name pairs.
 117→    pub fn edges(&self) -> Vec<Edge> {
 118→        let mut result = Vec::new();
 119→        for (caller_idx, callees) in self.adj.iter().enumerate() {
 120→            for &callee_idx in callees {
 121→                result.push(Edge {
 122→                    caller: self.nodes[caller_idx].clone(),
 123→                    callee: self.nodes[callee_idx].clone(),
 124→                });
 125→            }
 126→        }
 127→        result
 128→    }
 129→
 130→    /// Get the qualified names of all functions that `qualified_name` calls.
 131→    pub fn callees_of(&self, qualified_name: &str) -> Vec<&str> {
 132→        match self.node_index.get(qualified_name) {
 133→            Some(&idx) => self.adj[idx]
 134→                .iter()
 135→                .map(|&ci| self.nodes[ci].as_str())
 136→                .collect(),
 137→            None => Vec::new(),
 138→        }
 139→    }
 140→
 141→    /// Get the qualified names of all functions that call `qualified_name`.
 142→    pub fn callers_of(&self, qualified_name: &str) -> Vec<&str> {
 143→        match self.node_index.get(qualified_name) {
 144→            Some(&idx) => self.rev[idx]
 145→                .iter()
 146→                .map(|&ci| self.nodes[ci].as_str())
 147→                .collect(),
 148→            None => Vec::new(),
 149→        }
 150→    }
 151→
 152→    /// Compute topological layers (Kahn's algorithm).
 153→    ///
 154→    /// Layer 0 contains leaf functions (no outgoing calls to other project functions).
 155→    /// Each subsequent layer contains functions whose callees are all in earlier layers.
 156→    /// Functions involved in cycles are placed in the final layer.
 157→    pub fn topological_layers(&self) -> Vec<Vec<String>> {
 158→        let n = self.nodes.len();
 159→        if n == 0 {
 160→            return Vec::new();
 161→        }
 162→
 163→        // Out-degree for Kahn's (we layer bottom-up: leaves first).
 164→        let mut out_degree: Vec<usize> = self.adj.iter().map(|v| v.len()).collect();
 165→        let mut queue: Vec<usize> = Vec::new();
 166→        for (i, &deg) in out_degree.iter().enumerate() {
 167→            if deg == 0 {
 168→                queue.push(i);
 169→            }
 170→        }
 171→
 172→        let mut layers: Vec<Vec<String>> = Vec::new();
 173→        let mut visited = 0;
 174→
 175→        while !queue.is_empty() {
 176→            let mut layer = Vec::with_capacity(queue.len());
 177→            let mut next_queue = Vec::new();
 178→
 179→            for node in &queue {
 180→                layer.push(self.nodes[*node].clone());
 181→                visited += 1;
 182→
 183→                // For each caller of this node, decrement their out-degree.
 184→                for &caller in &self.rev[*node] {
 185→                    out_degree[caller] -= 1;
 186→                    if out_degree[caller] == 0 {
 187→                        next_queue.push(caller);
 188→                    }
 189→                }
 190→            }
 191→
 192→            layers.push(layer);
 193→            queue = next_queue;
 194→        }
 195→
 196→        // Any remaining nodes are in cycles.
 197→        if visited < n {
 198→            let cycle_layer: Vec<String> = (0..n)
 199→                .filter(|&i| out_degree[i] > 0)
 200→                .map(|i| self.nodes[i].clone())
 201→                .collect();
 202→            layers.push(cycle_layer);
 203→        }
 204→
 205→        layers
 206→    }
 207→
 208→    /// Detect strongly connected components using Tarjan's algorithm.
 209→    ///
 210→    /// Returns only SCCs with more than one member (actual cycles).
 211→    pub fn cycle_groups(&self) -> Vec<Vec<String>> {
 212→        let sccs = self.compute_sccs();
 213→        sccs.into_iter()
 214→            .filter(|scc| scc.len() > 1)
 215→            .map(|scc| scc.into_iter().map(|i| self.nodes[i].clone()).collect())
 216→            .collect()
 217→    }
 218→
 219→    /// Produce exploration batches in bottom-up dependency order.
 220→    ///
 221→    /// Collapses strongly connected components into single nodes, then
 222→    /// topologically sorts the resulting DAG. Each batch contains groups
 223→    /// of functions that can be explored in parallel because all their
 224→    /// dependencies appear in earlier batches.
 225→    ///
 226→    /// - Layer 0: leaf functions (no callees in the graph)
 227→    /// - Layer N: functions whose callees are all in layers 0..N-1
 228→    /// - Functions in cycles (SCCs with >1 member) are grouped and placed
 229→    ///   in the earliest valid layer
 230→    pub fn topological_batches(&self) -> Vec<ExplorationBatch> {
 231→        let n = self.nodes.len();
 232→        if n == 0 {
 233→            return Vec::new();
 234→        }
 235→
 236→        // Step 1: Compute all SCCs (including singletons).
 237→        let sccs = self.compute_sccs();
 238→        let num_sccs = sccs.len();
 239→
 240→        // Step 2: Map each node to its SCC index.
 241→        let mut node_to_scc = vec![0usize; n];
 242→        for (scc_idx, scc) in sccs.iter().enumerate() {
 243→            for &node in scc {
 244→                node_to_scc[node] = scc_idx;
 245→            }
 246→        }
 247→
 248→        // Step 3: Build condensation graph (DAG of SCCs).
 249→        let mut condensed_adj: Vec<HashSet<usize>> = vec![HashSet::new(); num_sccs];
 250→        for (caller, callees) in self.adj.iter().enumerate() {
 251→            let caller_scc = node_to_scc[caller];
 252→            for &callee in callees {
 253→                let callee_scc = node_to_scc[callee];
 254→                if caller_scc != callee_scc {
 255→                    condensed_adj[caller_scc].insert(callee_scc);
 256→                }
 257→            }
 258→        }
 259→
 260→        // Step 4: Kahn's algorithm on the condensation DAG (bottom-up: leaves first).
 261→        let mut out_degree: Vec<usize> = condensed_adj.iter().map(|s| s.len()).collect();
 262→
 263→        // Build reverse adjacency for the condensation.
 264→        let mut condensed_rev: Vec<Vec<usize>> = vec![Vec::new(); num_sccs];
 265→        for (from, tos) in condensed_adj.iter().enumerate() {
 266→            for &to in tos {
 267→                condensed_rev[to].push(from);
 268→            }
 269→        }
 270→
 271→        let mut queue: Vec<usize> = (0..num_sccs)
 272→            .filter(|&i| out_degree[i] == 0)
 273→            .collect();
 274→
 275→        let mut batches: Vec<ExplorationBatch> = Vec::new();
 276→        let mut layer = 0;
 277→
 278→        while !queue.is_empty() {
 279→            let mut groups: Vec<Vec<String>> = Vec::new();
 280→            let mut next_queue = Vec::new();
 281→
 282→            for &scc_idx in &queue {
 283→                let group: Vec<String> = sccs[scc_idx]
 284→                    .iter()
 285→                    .map(|&i| self.nodes[i].clone())
 286→                    .collect();
 287→                groups.push(group);
 288→
 289→                for &caller_scc in &condensed_rev[scc_idx] {
 290→                    out_degree[caller_scc] -= 1;
 291→                    if out_degree[caller_scc] == 0 {
 292→                        next_queue.push(caller_scc);
 293→                    }
 294→                }
 295→            }
 296→
 297→            batches.push(ExplorationBatch { layer, groups });
 298→            layer += 1;
 299→            queue = next_queue;
 300→        }
 301→
 302→        batches
 303→    }
 304→
 305→    /// Compute all strongly connected components (including singletons).
 306→    fn compute_sccs(&self) -> Vec<Vec<usize>> {
 307→        let n = self.nodes.len();
 308→        let mut state = TarjanState {
 309→            index_counter: 0,
 310→            stack: Vec::new(),
 311→            on_stack: vec![false; n],
 312→            node_index: vec![None; n],
 313→            lowlink: vec![0; n],
 314→            sccs: Vec::new(),
 315→        };
 316→
 317→        for i in 0..n {
 318→            if state.node_index[i].is_none() {
 319→                tarjan_strongconnect(i, &self.adj, &mut state);
 320→            }
 321→        }
 322→
 323→        state.sccs
 324→    }
 325→}
 326→
 327→/// Resolve a dependency symbol to a node index in the registry.
 328→///
 329→/// If only one function matches `symbol`, return it directly.
 330→/// If multiple match, try to disambiguate using `source_module` against file paths.
 331→fn resolve_dependency(
 332→    symbol: &str,
 333→    source_module: &str,
 334→    name_to_indices: &HashMap<&str, Vec<usize>>,
 335→    entries: &[crate::batch_analyze::FunctionEntry],
 336→) -> Option<usize> {
 337→    let candidates = name_to_indices.get(symbol)?;
 338→    if candidates.len() == 1 {
 339→        return Some(candidates[0]);
 340→    }
 341→
 342→    // Multiple candidates — try to match source_module against file paths.
 343→    if !source_module.is_empty() {
 344→        for &idx in candidates {
 345→            let path_str = entries[idx].file_path.to_string_lossy();
 346→            if path_str.contains(source_module) {
 347→                return Some(idx);
 348→            }
 349→        }
 350→    }
 351→
 352→    // Ambiguous — return first match as fallback.
 353→    Some(candidates[0])
 354→}
 355→
 356→/// Internal state for Tarjan's SCC algorithm.
 357→struct TarjanState {
 358→    index_counter: usize,
 359→    stack: Vec<usize>,
 360→    on_stack: Vec<bool>,
 361→    node_index: Vec<Option<usize>>,
 362→    lowlink: Vec<usize>,
 363→    sccs: Vec<Vec<usize>>,
 364→}
 365→
 366→/// Recursive strongconnect for Tarjan's algorithm.
 367→fn tarjan_strongconnect(v: usize, adj: &[Vec<usize>], state: &mut TarjanState) {
 368→    state.node_index[v] = Some(state.index_counter);
 369→    state.lowlink[v] = state.index_counter;
 370→    state.index_counter += 1;
 371→    state.stack.push(v);
 372→    state.on_stack[v] = true;
 373→
 374→    for &w in &adj[v] {
 375→        match state.node_index[w] {
 376→            None => {
 377→                tarjan_strongconnect(w, adj, state);
 378→                state.lowlink[v] = state.lowlink[v].min(state.lowlink[w]);
 379→            }
 380→            Some(_) if state.on_stack[w] => {
 381→                // w is on the stack, so it's in the current SCC.
 382→                state.lowlink[v] = state.lowlink[v].min(state.node_index[w].unwrap_or(0));
 383→            }
 384→            _ => {}
 385→        }
 386→    }
 387→
 388→    // If v is a root node, pop the SCC.
 389→    if state.lowlink[v] == state.node_index[v].unwrap_or(0) {
 390→        let mut scc = Vec::new();
 391→        while let Some(w) = state.stack.pop() {
 392→            state.on_stack[w] = false;
 393→            scc.push(w);
 394→            if w == v {
 395→                break;
 396→            }
 397→        }
 398→        state.sccs.push(scc);
 399→    }
 400→}
