 43→/// Compute the base path (without extension) for a function ID within a cache directory.
 44→///
 45→/// Mirrors the source tree structure:
 46→/// - `src/auth.ts:validateToken` → `src/auth.ts/validateToken`
 47→/// - `src/auth.ts:TokenValidator.validate` → `src/auth.ts/TokenValidator/validate`
 48→/// - `simpleFunc` → `simpleFunc`
 49→fn cache_base_path(cache_dir: &Path, function_id: &str) -> PathBuf {
 50→    let mut path = cache_dir.to_path_buf();
 51→
 52→    let (file_part, func_part) = match function_id.split_once(':') {
 53→        Some((f, func)) => (Some(f), func),
 54→        None => (None, function_id),
 55→    };
 56→
 57→    if let Some(file) = file_part {
 58→        for component in file.split('/') {
 59→            if !component.is_empty() {
 60→                path.push(sanitize_component(component));
 61→            }
 62→        }
 63→    }
 64→
 65→    match func_part.split_once('.') {
 66→        Some((class_name, method_name)) => {
 67→            path.push(sanitize_component(class_name));
 68→            path.push(sanitize_component(method_name));
 69→        }
 70→        None => {
 71→            path.push(sanitize_component(func_part));
 72→        }
 73→    }
 74→
 75→    path
 76→}
