        analysis2.params.reverse();

        let fp1 = compute_function_fingerprint(source, &analysis1);
        let fp2 = compute_function_fingerprint(source, &analysis2);

        // Params are sorted by name internally, so order shouldn't matter.
        assert_eq!(fp1, fp2);
