221→/// Extract the source text of a function from a file given line boundaries.
222→///
223→/// Reads lines `start_line..=end_line` (1-indexed) from the file and joins
224→/// them with newlines. Returns an error if the file cannot be read.
225→pub fn extract_function_source(
226→    file_path: &Path,
227→    start_line: u32,
228→    end_line: u32,
229→) -> Result<String, std::io::Error> {
230→    let contents = std::fs::read_to_string(file_path)?;
231→    let lines: Vec<&str> = contents.lines().collect();
232→    let start = (start_line as usize).saturating_sub(1);
233→    let end = (end_line as usize).min(lines.len());
234→    Ok(lines[start..end].join("\n"))
235→}
