 757→    /// Helper: collect all function names from a batch, flattened and sorted.
 758→    fn batch_names(batch: &ExplorationBatch) -> Vec<String> {
 759→        let mut names: Vec<String> = batch.groups.iter().flatten().cloned().collect();
 760→        names.sort();
 761→        names
 762→    }
 763→
 764→    /// Helper: find groups with more than one member in a batch.
 765→    fn cycle_groups_in_batch(batch: &ExplorationBatch) -> Vec<Vec<String>> {
 766→        batch
 767→            .groups
 768→            .iter()
 769→            .filter(|g| g.len() > 1)
 770→            .map(|g| {
 771→                let mut sorted = g.clone();
 772→                sorted.sort();
 773→                sorted
 774→            })
 775→            .collect()
 776→    }
