    assert!(plan.fresh.is_empty());

    assert_eq!(
        plan.stale_reasons["src/b.ts::helper"],
        StalenessReason::SourceChanged
    );
    assert!(matches!(
        &plan.stale_reasons["src/a.ts::main"],
        StalenessReason::CalleeChanged(callee) if callee == "src/b.ts::helper"
    ));
}

